# Analyzing the `detailed_error_context` for relevant insights about the evaluation status.
# Looking for explicit mentions of either success or failure for the evaluation.

results_summary = {
    "total": 0,
    "passed": 0,
    "failed": 0,
    "errored": 0
}

# Looking for any summary of results in the detailed log output
for line in detailed_error_context:
    if "result_counts" in line:
        parts = line.split(":")
        if len(parts) > 1:
            try:
                value = int(parts[1].strip().strip(',').strip())
                if "total" in line:
                    results_summary["total"] = value
                elif "passed" in line:
                    results_summary["passed"] = value
                elif "failed" in line:
                    results_summary["failed"] = value
                elif "errored" in line:
                    results_summary["errored"] = value
            except ValueError:
                continue

results_summary
